const input = $input.first().json;
const rawApi = input.api || input.domain;
const action = input.action;
const params = input.params || {};

// Domain alias mapping
const aliasMap = {google_calendar:'calendar',google_drive:'drive',google_sheets:'sheets',google_docs:'docs',google_slides:'slides'};
const api = aliasMap[rawApi] || rawApi;

const apiConfigs = {
  wordpress: {
    base_url: params.siteUrl ? (params.siteUrl + (params.siteUrl.endsWith('/wp-json') ? '' : '/wp-json')) : 'https://kahunaworkforce.com/wp-json',
    endpoints: {
      posts: { method: 'GET', path: '/wp/v2/posts', query: { per_page: params.per_page || 10, page: params.page || 1, status: params.status || 'publish', search: params.search || '' } },
      get_post: { method: 'GET', path: '/wp/v2/posts/' + (params.id || params.post_id || '{id}'), query: {} },
      create_post: { method: 'POST', path: '/wp/v2/posts', body: { title: params.title || '', content: params.content || '', status: params.status || 'draft', categories: params.categories || [] } },
      update_post: { method: 'PUT', path: '/wp/v2/posts/' + (params.id || params.post_id || '{id}'), body: params },
      delete_post: { method: 'DELETE', path: '/wp/v2/posts/' + (params.id || params.post_id || '{id}'), query: { force: params.force || false } },
      pages: { method: 'GET', path: '/wp/v2/pages', query: { per_page: params.per_page || 10, page: params.page || 1, status: params.status || 'publish' } },
      categories: { method: 'GET', path: '/wp/v2/categories', query: { per_page: params.per_page || 100 } },
      media: { method: 'GET', path: '/wp/v2/media', query: { per_page: params.per_page || 20, media_type: params.media_type || '' } }
    }
  },
  gmail: {
    base_url: 'https://gmail.googleapis.com/gmail/v1',
    endpoints: {
      list: { method: 'GET', path: '/users/me/messages', query: { maxResults: params.max_results || 20, q: params.query || '' } },
      read: { method: 'GET', path: `/users/me/messages/${params.message_id || '{message_id}'}`, query: { format: params.format || 'full' } },
      send: { method: 'POST', path: '/users/me/messages/send', body: { raw: Buffer.from(`To: ${params.to || ''}\r\nSubject: ${params.subject || ''}\r\nContent-Type: text/html; charset=utf-8\r\n\r\n${params.body || ''}`).toString('base64url') } },
      search: { method: 'GET', path: '/users/me/messages', query: { maxResults: params.max_results || 50, q: params.query || '' } },
      draft: { method: 'POST', path: '/users/me/drafts', body: { message: { raw: Buffer.from(`To: ${params.to || ''}\r\nSubject: ${params.subject || ''}\r\nContent-Type: text/html; charset=utf-8\r\n\r\n${params.body || ''}`).toString('base64url') } } },
      labels: { method: 'GET', path: '/users/me/labels', query: {} },
      reply: { method: 'POST', path: '/users/me/messages/send', body: { raw: Buffer.from(`To: ${params.to || ''}\r\nSubject: Re: ${params.subject || ''}\r\nIn-Reply-To: ${params.in_reply_to || ''}\r\nReferences: ${params.references || params.in_reply_to || ''}\r\nContent-Type: text/html; charset=utf-8\r\n\r\n${params.body || ''}`).toString('base64url'), threadId: params.thread_id || '' } },
      trash: { method: 'POST', path: `/users/me/messages/${params.message_id || '{message_id}'}/trash`, body: {} }
    }
  },
  calendar: {
    base_url: 'https://www.googleapis.com/calendar/v3',
    endpoints: {
      list: { method: 'GET', path: `/calendars/${encodeURIComponent(params.calendar_id || 'primary')}/events`, query: { timeMin: params.time_min || new Date().toISOString(), timeMax: params.time_max || new Date(Date.now()+7*86400000).toISOString(), maxResults: params.max_results || 50, singleEvents: true, orderBy: 'startTime' } },
      get: { method: 'GET', path: `/calendars/${encodeURIComponent(params.calendar_id || 'primary')}/events/${params.event_id || '{event_id}'}`, query: {} },
      create: { method: 'POST', path: `/calendars/${encodeURIComponent(params.calendar_id || 'primary')}/events`, body: { summary: params.summary || '', description: params.description || '', start: { dateTime: params.start, timeZone: params.timezone || 'America/Chicago' }, end: { dateTime: params.end, timeZone: params.timezone || 'America/Chicago' }, attendees: (params.attendees || []).map(e => ({email:e})) } },
      update: { method: 'PATCH', path: `/calendars/${encodeURIComponent(params.calendar_id || 'primary')}/events/${params.event_id || '{event_id}'}`, body: params.update || {} },
      delete: { method: 'DELETE', path: `/calendars/${encodeURIComponent(params.calendar_id || 'primary')}/events/${params.event_id || '{event_id}'}`, body: {} }
    }
  },
  drive: {
    base_url: 'https://www.googleapis.com/drive/v3',
    endpoints: {
      list: { method: 'GET', path: '/files', query: { q: params.folder_id ? `'${params.folder_id}' in parents and trashed=false` : 'trashed=false', pageSize: params.max_results || 100, fields: 'nextPageToken,files(id,name,mimeType,size,modifiedTime,webViewLink,parents)', orderBy: 'modifiedTime desc' } },
      get: { method: 'GET', path: `/files/${params.file_id || '{file_id}'}`, query: { fields: 'id,name,mimeType,size,modifiedTime,webViewLink,description,parents,permissions' } },
      search: { method: 'GET', path: '/files', query: { q: `name contains '${params.query || ''}' and trashed=false`, pageSize: params.max_results || 50, fields: 'nextPageToken,files(id,name,mimeType,size,modifiedTime,webViewLink)', orderBy: 'modifiedTime desc' } },
      create: { method: 'POST', path: '/files', body: { name: params.name || 'Untitled', mimeType: params.mime_type || 'application/vnd.google-apps.document', parents: params.folder_id ? [params.folder_id] : [] } },
  copy: { method: 'POST', path: `/files/${params.file_id || '{file_id}'}/copy`, body: { name: params.name || undefined, parents: params.folder_id ? [params.folder_id] : undefined } },
      move: { method: 'PATCH', path: `/files/${params.file_id || '{file_id}'}`, query: { addParents: params.target_folder_id || '', removeParents: params.source_folder_id || '' }, body: {} },
      delete: { method: 'PATCH', path: `/files/${params.file_id || '{file_id}'}`, body: { trashed: true } },
      download: { method: 'GET', path: `/files/${params.file_id || '{file_id}'}`, query: { alt: 'media' } }
    }
  },
  sheets: {
    base_url: 'https://sheets.googleapis.com/v4',
    endpoints: {
      list: { method: 'GET', path: `/spreadsheets/${params.spreadsheet_id || '{spreadsheet_id}'}`, query: { fields: 'spreadsheetId,properties.title,sheets.properties' } },
      read: { method: 'GET', path: `/spreadsheets/${params.spreadsheet_id || '{spreadsheet_id}'}/values/${encodeURIComponent(params.range || 'Sheet1')}`, query: { valueRenderOption: params.render_option || 'FORMATTED_VALUE' } },
      write: { method: 'PUT', path: `/spreadsheets/${params.spreadsheet_id || '{spreadsheet_id}'}/values/${encodeURIComponent(params.range || 'Sheet1')}`, query: { valueInputOption: params.input_option || 'USER_ENTERED' }, body: { range: params.range || 'Sheet1', majorDimension: 'ROWS', values: params.values || [] } },
      append: { method: 'POST', path: `/spreadsheets/${params.spreadsheet_id || '{spreadsheet_id}'}/values/${encodeURIComponent(params.range || 'Sheet1')}:append`, query: { valueInputOption: params.input_option || 'USER_ENTERED', insertDataOption: 'INSERT_ROWS' }, body: { values: params.values || [] } },
      clear: { method: 'POST', path: `/spreadsheets/${params.spreadsheet_id || '{spreadsheet_id}'}/values/${encodeURIComponent(params.range || 'Sheet1')}:clear`, body: {} },
      create: { method: 'POST', path: '/spreadsheets', body: { properties: { title: params.title || 'New Spreadsheet' }, sheets: [{ properties: { title: params.sheet_name || 'Sheet1' } }] } }
    }
  },
  docs: {
    base_url: 'https://docs.googleapis.com/v1',
    endpoints: {
      get: { method: 'GET', path: `/documents/${params.document_id || '{document_id}'}`, query: {} },
      create: { method: 'POST', path: '/documents', body: { title: params.title || 'Untitled Document' } },
      append: { method: 'POST', path: `/documents/${params.document_id || '{document_id}'}:batchUpdate`, body: { requests: [{ insertText: { location: { index: params.index || 1 }, text: params.text || '' } }] } }
    }
  },
  slides: {
    base_url: 'https://slides.googleapis.com/v1',
    endpoints: {
      get: { method: 'GET', path: `/presentations/${params.presentation_id || '{presentation_id}'}`, query: {} },
      create: { method: 'POST', path: '/presentations', body: { title: params.title || 'Untitled Presentation' } }
    }
  },
  slack: {
    base_url: 'https://slack.com/api',
    endpoints: {
      list_channels: { method: 'GET', path: '/conversations.list', query: { types: params.types || 'public_channel,private_channel', limit: params.limit || 200 } },
      send: { method: 'POST', path: '/chat.postMessage', body: { channel: params.channel || '{channel}', text: params.text || '', blocks: params.blocks || undefined } },
      search: { method: 'GET', path: '/search.messages', query: { query: params.query || '', count: params.limit || 20 } },
      read_channel: { method: 'GET', path: '/conversations.history', query: { channel: params.channel || '{channel}', limit: params.limit || 50 } },
      read_thread: { method: 'GET', path: '/conversations.replies', query: { channel: params.channel || '{channel}', ts: params.ts || params.thread_ts || '{ts}', limit: params.limit || 50 } },
      list_users: { method: 'GET', path: '/users.list', query: { limit: params.limit || 200 } },
      reactions_add: { method: 'POST', path: '/reactions.add', body: { channel: params.channel || '{channel}', name: params.name || '{emoji}', timestamp: params.timestamp || params.ts || '{ts}' } },
      upload_file: { method: 'POST', path: '/files.uploadV2', body: { channel_id: params.channel_id || params.channel || '{channel}', content: params.content || '', filename: params.filename || 'file.txt', title: params.title || '' } }
    }
  },
  notion: {
    base_url: 'https://api.notion.com/v1',
    endpoints: {
      search: { method: 'POST', path: '/search', body: { query: params.query || '', page_size: params.limit || 10 } },
      get_page: { method: 'GET', path: `/pages/${params.page_id || '{page_id}'}`, query: {} },
      create_page: { method: 'POST', path: '/pages', body: params.page || { parent: { database_id: params.database_id || params.data_source_id || '{database_id}' }, properties: params.properties || {}, ...(params.markdown ? { markdown: params.markdown } : {}) } },
      update_page: { method: 'PATCH', path: `/pages/${params.page_id || '{page_id}'}`, body: { properties: params.properties || {} } },
      query_database: { method: 'POST', path: `/databases/${params.database_id || params.data_source_id || '{database_id}'}/query`, body: { filter: params.filter || undefined, sorts: params.sorts || undefined, page_size: params.limit || 100 } },
      get_database: { method: 'GET', path: `/databases/${params.database_id || params.data_source_id || '{database_id}'}`, query: {} },
      create_database: { method: 'POST', path: '/databases', body: { parent: params.parent || { page_id: params.page_id || '{page_id}' }, title: params.title || [], properties: params.properties || {} } },
      get_block_children: { method: 'GET', path: `/blocks/${params.block_id || '{block_id}'}/children`, query: { page_size: params.limit || 100 } },
      get_markdown: { method: 'GET', path: `/pages/${params.page_id || '{page_id}'}/markdown`, query: {} },
      update_markdown: { method: 'PATCH', path: `/pages/${params.page_id || '{page_id}'}/markdown`, body: { markdown: params.markdown || '' } },
      create_page_markdown: { method: 'POST', path: '/pages', body: { parent: { database_id: params.database_id || params.data_source_id || '{database_id}' }, properties: params.properties || {}, markdown: params.markdown || '' } },
      query_data_source: { method: 'POST', path: `/data_sources/${params.data_source_id || '{data_source_id}'}/query`, body: { filter: params.filter || undefined, sorts: params.sorts || undefined, page_size: params.limit || 100 } },
      get_data_source: { method: 'GET', path: `/data_sources/${params.data_source_id || '{data_source_id}'}`, query: {} },
      create_data_source: { method: 'POST', path: '/data_sources', body: { parent: params.parent || {}, properties: params.properties || {} } },
      list_templates: { method: 'GET', path: `/data_sources/${params.data_source_id || '{data_source_id}'}/templates`, query: {} }
    }
  },

  youtube: {
    base_url: 'https://www.googleapis.com/youtube/v3',
    endpoints: {
      search: { method: 'GET', path: '/search', query: { part: 'snippet', q: params.query || '', maxResults: params.limit || 10, type: params.type || 'video' } },
      channel_stats: { method: 'GET', path: '/channels', query: { part: 'snippet,statistics', id: params.channel_id || undefined, mine: params.channel_id ? undefined : 'true' } },
      video_stats: { method: 'GET', path: '/videos', query: { part: 'snippet,statistics', id: params.video_id || '{video_id}' } },
      playlists: { method: 'GET', path: '/playlists', query: { part: 'snippet,contentDetails', channelId: params.channel_id || undefined, mine: params.channel_id ? undefined : 'true', maxResults: params.limit || 10 } }
    }
  },
  linkedin: {
    base_url: 'https://api.linkedin.com',
    endpoints: {
      profile: { method: 'GET', path: '/v2/userinfo', query: {} },
      create_post: { method: 'POST', path: '/v2/ugcPosts', body: params.post_body || { author: params.author_urn, lifecycleState: 'PUBLISHED', specificContent: { 'com.linkedin.ugc.ShareContent': { shareCommentary: { text: params.text || '' }, shareMediaCategory: 'NONE' } }, visibility: { 'com.linkedin.ugc.MemberNetworkVisibility': params.visibility || 'PUBLIC' } } }
    }
  },
  twitter: {
    base_url: 'https://api.twitter.com/2',
    endpoints: {
      search: { method: 'GET', path: '/tweets/search/recent', query: { query: params.query || '', max_results: params.limit || 10 } },
      get_user: { method: 'GET', path: `/users/by/username/${params.username || '{username}'}`, query: { 'user.fields': 'description,public_metrics,created_at' } },
      post: { method: 'POST', path: '/tweets', body: { text: params.text || '' } },
      me: { method: 'GET', path: '/users/me', query: { 'user.fields': 'description,public_metrics,created_at' } }
    }
  },
  google_my_business: {
    base_url: 'https://mybusinessaccountmanagement.googleapis.com/v1',
    endpoints: {
      accounts: { method: 'GET', path: '/accounts', query: {} },
      locations: { method: 'GET', path: `/accounts/${params.account_id || '{account_id}'}/locations`, query: { readMask: 'name,title,storefrontAddress,websiteUri' } },
      reviews: { method: 'GET', path: `/${params.location_name || '{location_name}'}/reviews`, query: {} }
    }
  },
  onedrive: {
    base_url: 'https://graph.microsoft.com/v1.0',
    endpoints: {
      list_files: { method: 'GET', path: '/me/drive/root/children', query: { '$select': 'id,name,size,lastModifiedDateTime,webUrl' } },
      get_file: { method: 'GET', path: `/me/drive/items/${params.item_id || '{item_id}'}`, query: {} },
      search: { method: 'GET', path: `/me/drive/search(q='${params.query || ''}')`, query: { '$top': params.limit || 20 } },
      create_folder: { method: 'POST', path: '/me/drive/root/children', body: { name: params.name || 'New Folder', folder: {}, '@microsoft.graph.conflictBehavior': 'rename' } },
      upload: { method: 'PUT', path: `/me/drive/root:/${params.filename || '{filename}'}:/content`, body: params.content || '' }
    }
  },
  excel: {
    base_url: 'https://graph.microsoft.com/v1.0',
    endpoints: {
      list_workbooks: { method: 'GET', path: "/me/drive/search(q='.xlsx')", query: { '$top': params.limit || 20, '$select': 'id,name,lastModifiedDateTime,webUrl' } },
      list_sheets: { method: 'GET', path: `/me/drive/items/${params.file_id || '{file_id}'}/workbook/worksheets`, query: {} },
      read_range: { method: 'GET', path: `/me/drive/items/${params.file_id || '{file_id}'}/workbook/worksheets/${encodeURIComponent(params.sheet || 'Sheet1')}/range(address='${params.range || 'A1:Z100'}')`, query: {} },
      write_range: { method: 'PATCH', path: `/me/drive/items/${params.file_id || '{file_id}'}/workbook/worksheets/${encodeURIComponent(params.sheet || 'Sheet1')}/range(address='${params.range || '{range}'}')`, body: { values: params.values || [] } },
      list_tables: { method: 'GET', path: `/me/drive/items/${params.file_id || '{file_id}'}/workbook/tables`, query: {} }
    }
  },
  todo: {
    base_url: 'https://graph.microsoft.com/v1.0',
    endpoints: {
      list_lists: { method: 'GET', path: '/me/todo/lists', query: {} },
      list_tasks: { method: 'GET', path: `/me/todo/lists/${params.list_id || '{list_id}'}/tasks`, query: {} },
      create_task: { method: 'POST', path: `/me/todo/lists/${params.list_id || '{list_id}'}/tasks`, body: { title: params.title || '', importance: params.importance || 'normal' } },
      complete_task: { method: 'PATCH', path: `/me/todo/lists/${params.list_id || '{list_id}'}/tasks/${params.task_id || '{task_id}'}`, body: { status: 'completed' } }
    }
  },
  outlook: {
    base_url: 'https://graph.microsoft.com/v1.0/me',
    endpoints: {
      list: { method: 'GET', path: '/messages', query: { '$top': params.limit || 20, '$orderby': 'receivedDateTime desc', '$select': 'id,subject,from,receivedDateTime,isRead,bodyPreview' } },
      send: { method: 'POST', path: '/sendMail', body: { message: { subject: params.subject || '', body: { contentType: 'HTML', content: params.body || '' }, toRecipients: (params.to ? (Array.isArray(params.to) ? params.to : [params.to]) : []).map(e => ({emailAddress:{address:e}})) } } }
    }
  }
};

const config = apiConfigs[api];
if (!config) {
  return [{ json: { error: true, message: `Unknown API: ${api}. Available: ${Object.keys(apiConfigs).join(', ')}` } }];
}

const endpoint = config.endpoints[action];
if (!endpoint) {
  return [{ json: { error: true, message: `Unknown action '${action}' for ${api}. Available: ${Object.keys(config.endpoints).join(', ')}` } }];
}

// Build query string into URL (avoids empty query param bug in HTTP Request nodes)
let fullUrl = config.base_url + endpoint.path;
const queryObj = endpoint.query || {};
const qEntries = Object.entries(queryObj).filter(([k, v]) => k && v !== undefined && v !== null && v !== '');
if (qEntries.length > 0) {
  fullUrl += (fullUrl.includes('?') ? '&' : '?') + qEntries.map(([k, v]) => encodeURIComponent(k) + '=' + encodeURIComponent(v)).join('&');
}

return [{
  json: {
    method: endpoint.method,
    url: fullUrl,
    query: {},
    body: endpoint.body || {},
    api: api,
    action: action
  }
}];

const input = $input.first().json;
const request = $('Build API Request').first().json;

if (input.error || input.statusCode >= 400) {
  return [{
    json: {
      error: true,
      api: request.api,
      action: request.action,
      status_code: input.statusCode || 500,
      message: input.message || input.error || 'API call failed',
      raw_error: input
    }
  }];
}

return [{
  json: {
    success: true,
    api: request.api,
    action: request.action,
    data: input.data || input.body || input,
    metadata: {
      timestamp: new Date().toISOString(),
      execution_id: $execution.id
    }
  }
}];

// Normalize webhook input + verify internal auth
const input = $input.first().json;
const data = input.body || input;

// Security: verify internal handler secret
const headers = input.headers || {};
const secret = headers['x-handler-secret'] || data._handler_secret || '';
const EXPECTED = $vars.GW_HANDLER_INTERNAL_SECRET;

if (secret !== EXPECTED && headers['x-handler-secret'] !== EXPECTED) {
  // Allow Execute Workflow Trigger calls (no headers) but block raw webhook calls without secret
  const isWebhook = !!input.headers;
  if (isWebhook) {
    return [{ json: { error: true, message: 'Unauthorized handler call', status_code: 403 } }];
  }
}

// Clean up internal field
if (data._handler_secret) delete data._handler_secret;
return [{ json: data }];
